sql:
SELECT name, captain_id, tourney_id
FROM teams
WHERE status = 'registered';

SELECT tournaments.name AS TournamentName, divisions.name AS DivisionName
FROM tournaments
JOIN divisions ON tournaments.tourney_id = divisions.tourney_id;

SELECT tourney_id, AVG(num_teams) as average_teams
FROM tournaments
GROUP BY tourney_id;

SELECT AVG(registration_fee) AS AverageRegistrationFee
FROM divisions
WHERE name = 'Challenger 4.5+';

external_knowledge:
- "a shadow of Chicago" refers to tournament names that contain 'chicagol';
- "residing in the heart of Chicago, IL" means the location is specified as 'Chicago, IL';
- "aren’t yet part of the past" signifies that the status is not 'finished';
- "first and last beats" refer to the start and end dates of the tournaments.

- "arenas" metaphorically refers to the tournaments;
- "divisions within them" refers to the divisions in each tournament;
- "waves of victory" is a metaphor for the scores achieved in competitions;
- "rhythm of their average ebb and flow" metaphorically means the average scores.

sql:
SELECT MAX(score) AS highest_score
FROM scores
WHERE match_id = (SELECT match_id FROM matches WHERE start_time = '2022-01-01 14:00:00');
